import{_ as i,o as s,c as a,ak as t}from"./chunks/framework.DkeEmzcj.js";const b=JSON.parse('{"title":"Question Submissions - Punjab Educare","description":"High-level overview of how teachers contribute questions, with review and publication safeguards.","frontmatter":{"title":"Question Submissions - Punjab Educare","description":"High-level overview of how teachers contribute questions, with review and publication safeguards."},"headers":[],"relativePath":"punjab-educare/question-submissions.md","filePath":"punjab-educare/question-submissions.md","lastUpdated":1772241126000}'),n={name:"punjab-educare/question-submissions.md"};function o(r,e,l,u,c,d){return s(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="question-submissions" tabindex="-1">Question Submissions <a class="header-anchor" href="#question-submissions" aria-label="Permalink to “Question Submissions”">​</a></h1><p>Punjab Educare supports teacher-contributed questions through a guided submission workflow with internal review before publication to the main question bank.</p><h2 id="where-submissions-happen" tabindex="-1">Where submissions happen <a class="header-anchor" href="#where-submissions-happen" aria-label="Permalink to “Where submissions happen”">​</a></h2><p>Question submission is available across both mobile and desktop apps. The workflow and rules are consistent to keep review and publishing predictable.</p><h2 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to “Workflow”">​</a></h2><ol><li>Review requirements and confirm eligibility to submit.</li><li>Select academic context (class, subject, topic, and language where applicable).</li><li>Enter questions using a structured editor designed for consistent formatting and review.</li><li>Submit for internal review.</li><li>Publication to the main bank occurs only after approval by the trusted internal admin team member.</li></ol><h2 id="requirements-rules" tabindex="-1">Requirements &amp; rules <a class="header-anchor" href="#requirements-rules" aria-label="Permalink to “Requirements &amp; rules”">​</a></h2><p><strong>Minimum submission size</strong></p><ul><li>A minimum of 10 questions is required per submission.</li></ul><p><strong>Supported formats</strong></p><ul><li>Multiple choice</li><li>True/False</li></ul><p><strong>Consistency rule</strong></p><ul><li>For multiple choice questions, the correct answer is placed in option 1 and 4 options are required.</li></ul><h2 id="review-and-quality-control" tabindex="-1">Review and quality control <a class="header-anchor" href="#review-and-quality-control" aria-label="Permalink to “Review and quality control”">​</a></h2><ul><li>Every submission is reviewed before publication.</li><li>This review step is used to maintain quality, correctness, and curriculum alignment across classes and subjects.</li></ul><h2 id="submission-restrictions" tabindex="-1">Submission restrictions <a class="header-anchor" href="#submission-restrictions" aria-label="Permalink to “Submission restrictions”">​</a></h2><p>Teachers may be temporarily restricted from submitting new questions based on prior submission outcomes (for example, repeated rejections). When restricted, submissions are blocked until eligibility is restored.</p><h2 id="consent-and-retention" tabindex="-1">Consent and retention <a class="header-anchor" href="#consent-and-retention" aria-label="Permalink to “Consent and retention”">​</a></h2><p>By submitting a question set, teachers confirm:</p><ul><li>The provided information and questions are correct to the best of their knowledge.</li><li>They consent to permanent publication and unrestricted use of the submitted questions (as described in the <a href="/products/punjab-educare/intellectual-property-collaboration-notice">Intellectual Property &amp; Collaboration Notice</a>).</li><li>Submitted questions cannot be deleted after submission, including after an account deletion request.</li></ul><div class="info custom-block"><p class="custom-block-title">Why consent exists</p><p>The question bank is designed as a curated, long-lived resource for learners. The submission workflow (review → approval → publication) is structured to support quality control, long-term reuse, and continuity of the bank over time.</p></div><h2 id="guides" tabindex="-1">Guides <a class="header-anchor" href="#guides" aria-label="Permalink to “Guides”">​</a></h2><h3 id="mobile-apps" tabindex="-1">Mobile Apps <a class="header-anchor" href="#mobile-apps" aria-label="Permalink to “Mobile Apps”">​</a></h3><ul><li>Video walkthrough: <a href="https://youtu.be/ZOHHgR2bnrU" target="_blank" rel="noreferrer">YouTube</a></li><li>PDF guide: <a href="https://drive.google.com/file/d/1BK5-6jN4KPP_VML0HN8wkRb1EFh3m7ux/view?usp=drive_link" target="_blank" rel="noreferrer">Google Drive</a></li></ul><h3 id="desktop-apps" tabindex="-1">Desktop Apps <a class="header-anchor" href="#desktop-apps" aria-label="Permalink to “Desktop Apps”">​</a></h3><p><em>Coming soon</em></p>',26)])])}const h=i(n,[["render",o]]);export{b as __pageData,h as default};
